let subject = "";
try {
  subject = $('Email Trigger (IMAP)').item.json.subject;
} catch (error) {
  subject = $json.subject || "";
}

if (!subject) subject = "NO SE ENCONTRO EL ASUNTO";

const match = subject.match(/(TK-\d+)/i);

return {
  ticket_id: match ? match[1] : null
};

// --- FUNCIONES DE SEGURIDAD ---
function buscarDato(nombreNodo, campo, valorPorDefecto) {
  try {
    if ($(nombreNodo) && $(nombreNodo).item && $(nombreNodo).item.json) {
      const valor = $(nombreNodo).item.json[campo];
      return (valor !== undefined && valor !== null) ? valor : valorPorDefecto;
    } 
    else if ($(nombreNodo) && $(nombreNodo).first && $(nombreNodo).first().json) {
       const valor = $(nombreNodo).first().json[campo];
       return (valor !== undefined && valor !== null) ? valor : valorPorDefecto;
    }
    return valorPorDefecto;
  } catch (error) {
    return valorPorDefecto;
  }
}

// --- 1. OBTENCIÓN DE DATOS ---
const fecha = new Date().toLocaleString('es-AR', { timeZone: 'America/Argentina/Buenos_Aires' });

const idTicket = buscarDato('Extraer ID', 'ticket_id', "SIN_ID");
const nombreCliente = buscarDato('Get many rows', 'nombre', "Cliente");
const textoCliente = buscarDato('Email Trigger (IMAP)', 'textPlain', "Sin mensaje legible.");
const rawIA = buscarDato('Basic LLM Chain1', 'text', "");

// --- 2. PROCESAMIENTO INTELIGENTE ---
let respuestaParaCliente = rawIA;
let dbModulo = "General"; 
let dbPrioridad = "Media";
let dbDatosFaltantes = "";

try {
  const jsonLimpio = rawIA.replace(/```json/g, '').replace(/```/g, '').trim();

  if (jsonLimpio.startsWith('{')) {
    const objetoIA = JSON.parse(jsonLimpio);
    dbModulo = objetoIA.modulo || "General";
    dbPrioridad = objetoIA.prioridad || "Media";

    if (objetoIA.datos_faltantes && Array.isArray(objetoIA.datos_faltantes)) {
      dbDatosFaltantes = objetoIA.datos_faltantes.map((pregunta, index) => `${index + 1}. ${pregunta}`).join('\n');
    }

    if (objetoIA.datos_faltantes && Array.isArray(objetoIA.datos_faltantes) && objetoIA.datos_faltantes.length > 0) {
      respuestaParaCliente = `
        Hemos analizado su reporte sobre <b>"${objetoIA.resumen || 'el incidente'}"</b>.<br>
        Para poder resolverlo, necesitamos que nos brinde la siguiente información:
        <ul>
          <li>${objetoIA.datos_faltantes.join('</li><li>')}</li>
        </ul>
      `;
    } else if (objetoIA.respuesta) {
      respuestaParaCliente = objetoIA.respuesta;
    } else {
       respuestaParaCliente = jsonLimpio;
    }
  }
} catch (e) {
  respuestaParaCliente = rawIA.replace(/```json/g, '').replace(/```/g, '');
  dbDatosFaltantes = rawIA;
}

function hacerHtmlBonito(contenido, nombre) {
  let cuerpo = contenido;
  if (!cuerpo.includes('<ul')) {
      cuerpo = cuerpo.replace(/\n/g, '<br>');
  }

  return `
    <div style="font-family: Arial, sans-serif; color: #333333; line-height: 1.6; font-size: 14px;">
      Hola <b>${nombre}</b>,<br><br>
      Gracias por contactar a Soporte.<br><br>
      ${cuerpo}
      <br><br>
      <hr style="border: 0; border-top: 1px solid #eeeeee;">
      <small style="color: #888888;">Ticket ID: ${idTicket}</small>
    </div>
  `;
}

// --- 4. PREPARACIÓN BASE DE DATOS (AQUÍ ESTÁ LA MAGIA) ---
const clienteSafe = (textoCliente || "").replace(/'/g, "''");
const iaSafe = respuestaParaCliente.toString().replace(/<[^>]*>?/gm, ' ').replace(/'/g, "''");

// ESTE ES EL FORMATO QUE VERÁS EN EL DASHBOARD
const bloqueHistorial = `
[CLIENTE - ${fecha}]:
${clienteSafe}

----------------------------------------

[SOPORTE IA - ${fecha}]:
${iaSafe}

----------------------------------------
`;

return {
  id_ticket_limpio: idTicket.toString().trim(), 
  actualizacion_historial: bloqueHistorial,
  email_html_bonito: hacerHtmlBonito(respuestaParaCliente, nombreCliente),
  modulo_ticket: dbModulo,
  prioridad_ticket: dbPrioridad,
  datos_faltantes_lista: dbDatosFaltantes
};

const fecha = new Date().toLocaleString('es-AR', { timeZone: 'America/Argentina/Buenos_Aires' });

// Datos simples para el mensaje de cambio de estado
const mensajeSistema = "Su respuesta ha sido recibida correctamente. El estado de su ticket ha cambiado a 'En Revisión'.";

const emailHtml = `
  <div style="font-family: Arial, sans-serif; color: #333;">
    ${mensajeSistema}
    <br><br>
    Saludos,<br><b>Equipo de Soporte</b>
  </div>
`;

const logSistema = `
[SISTEMA - ${fecha}]:
${mensajeSistema}

----------------------------------------
`;

return {
  nuevo_estado: "En Revisión",
  actualizacion_sistema: logSistema,
  email_respuesta: emailHtml
};

